import{c as t,Q as a,j as s,m as r}from"./chunks/framework.BBA2dIOt.js";const o="/ember/assets/reader-desktop.hbPUnGN6.png",i="/ember/assets/article-desktop.DwoU25jd.png",n="/ember/assets/settings-preferences-desktop.8zP_13b5.png",l="/ember/assets/settings-llm-desktop.C97YYjsf.png",d="/ember/assets/settings-email-desktop.Dgyn5M0R.png",c="/ember/assets/login-desktop.BzdZgBwa.png",h="/ember/assets/reader-mobile.CKW_nUFB.png",p="/ember/assets/article-mobile.DuqtnvWS.png",v=JSON.parse('{"title":"Screenshots","description":"","frontmatter":{},"headers":[],"relativePath":"screenshots.md","filePath":"screenshots.md","lastUpdated":1779997819000}'),m={name:"screenshots.md"};function g(u,e,b,f,k,_){return a(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="screenshots" tabindex="-1">Screenshots <a class="header-anchor" href="#screenshots" aria-label="Permalink to &quot;Screenshots&quot;">​</a></h1><p>Captured against the live docker stack via <code>make docs-screenshots</code> (a Playwright script under <code>web/scripts/screenshots.mjs</code>). All shots are auto-regeneratable; the build doesn&#39;t depend on them being current — re-run the script anytime the UI shifts.</p><h2 id="three-pane-reader" tabindex="-1">Three-pane reader <a class="header-anchor" href="#three-pane-reader" aria-label="Permalink to &quot;Three-pane reader&quot;">​</a></h2><p>The default layout: sidebar of folders + feeds, the article list, and the reader. Keyboard navigation (<code>j</code> / <code>k</code> / <code>r</code> / <code>m</code> / <code>s</code> / <code>?</code>), drag-to-reorder folders and feeds within them.</p><p><img src="'+o+'" alt="Reader, desktop"></p><h2 id="article-view" tabindex="-1">Article view <a class="header-anchor" href="#article-view" aria-label="Permalink to &quot;Article view&quot;">​</a></h2><p>Summary card sits between the title and the body — paragraph lead + factual bullets. AI ad-stripping removes newsletter signups, podcast promos, and &quot;Comments&quot; trailers from the body before display.</p><p><img src="'+i+'" alt="Article, desktop"></p><h2 id="settings-—-preferences" tabindex="-1">Settings — preferences <a class="header-anchor" href="#settings-—-preferences" aria-label="Permalink to &quot;Settings — preferences&quot;">​</a></h2><p>Theme picker (8 presets + custom palette), density toggle, AI summary card on/off.</p><p><img src="'+n+'" alt="Settings, preferences"></p><h2 id="settings-—-language-model-admin" tabindex="-1">Settings — language model (admin) <a class="header-anchor" href="#settings-—-language-model-admin" aria-label="Permalink to &quot;Settings — language model (admin)&quot;">​</a></h2><p>Host probe (RAM/CPU/GPU) with a model recommendation. Installed-model table with per-row switch + delete. Pull form for new models. Sliders for temperature, top_p, num_ctx.</p><p><img src="'+l+'" alt="Settings, LLM"></p><h2 id="settings-—-email-smtp-admin" tabindex="-1">Settings — email / SMTP (admin) <a class="header-anchor" href="#settings-—-email-smtp-admin" aria-label="Permalink to &quot;Settings — email / SMTP (admin)&quot;">​</a></h2><p>Overlay the <code>EMBER_SMTP_*</code> env defaults with admin-edited values that take effect at runtime (digest sender re-resolves each tick). Send a one-off test email to verify the relay. Below it, the initial-backlog window controls how much history is ingested when a new feed is added.</p><p><img src="'+d+'" alt="Settings, Email / SMTP"></p><h2 id="login" tabindex="-1">Login <a class="header-anchor" href="#login" aria-label="Permalink to &quot;Login&quot;">​</a></h2><p>Paper-and-ink split layout. Branding (app name, page title, favicon) is admin-configurable from Settings → Branding.</p><p><img src="'+c+'" alt="Login, desktop"></p><h2 id="mobile" tabindex="-1">Mobile <a class="header-anchor" href="#mobile" aria-label="Permalink to &quot;Mobile&quot;">​</a></h2><p>≤900px viewport: sidebar collapses into an off-canvas drawer. Article list and reader take turns at full width — selecting an article switches to the reader; a back arrow returns to the list. Below 520px, the brand text hides so the search bar has room.</p><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(220px, 1fr));gap:16px;margin:24px 0;"><p><img src="'+h+'" alt="Reader, mobile"></p><p><img src="'+p+'" alt="Article, mobile"></p></div><h2 id="themes" tabindex="-1">Themes <a class="header-anchor" href="#themes" aria-label="Permalink to &quot;Themes&quot;">​</a></h2><p>Eight presets cover light, dark, and accessibility needs. The &quot;Custom&quot; theme lets you pick 3 colors (paper, ink, accent) and the rest of the palette derives via CSS <code>color-mix()</code>.</p><ul><li><strong>Auto</strong> — follows the OS <code>prefers-color-scheme</code>.</li><li><strong>Light</strong> / <strong>Dark</strong> — paper-and-ink defaults.</li><li><strong>Solarized</strong> — Ethan Schoonover&#39;s classic palette.</li><li><strong>Sepia</strong> — warm browns, e-reader friendly.</li><li><strong>Nord</strong> — cool blue-gray dark.</li><li><strong>Gruvbox</strong> — warm-tinted dark by morhetz.</li><li><strong>High contrast</strong> — black / white / yellow for low-vision users.</li><li><strong>Custom</strong> — your three colors.</li></ul><h2 id="regenerating-these" tabindex="-1">Regenerating these <a class="header-anchor" href="#regenerating-these" aria-label="Permalink to &quot;Regenerating these&quot;">​</a></h2><p>Bring up the docker stack, subscribe to at least one starter pack, then:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs-screenshots</span></span></code></pre></div><p>The script logs in, takes a tour through each surface at both desktop (1440×900 @ 2x) and mobile (390×844 @ 3x) viewports, and writes PNGs into <code>docs/public/screenshots/</code>. Commit the result — it&#39;s the same as any docs change.</p>',30)])])}const S=t(m,[["render",g]]);export{v as __pageData,S as default};
